const keywords = ["ai", "automation", "integration", "saas"];

return items.filter(item => {
  const text = (item.json.article || "").toLowerCase();

  return keywords.some(keyword => text.includes(keyword));
});

const seen = new Set();

return items.filter(item => {
  const title = item.json.article.slice(0, 100); 

  if (seen.has(title)) {
    return false;
  }

  seen.add(title);
  return true;
});

return items.map(item => {
  const e = item.json.engagement;

  // Simple scoring formula
  const score = (e.likes * 1) + (e.shares * 2) + (e.comments * 3);

  return {
    json: {
      ...item.json,
      trendScore: score
    }
  };
});

return items.slice(0, 10).map(item => {
  const data = item.json;

  const title = data.title || "";
  const description = data.description || "";
  const content = data.content || "";

  const fullText = `${title}. ${description}. ${content}`;

  return {
    json: {

      article: fullText,


      source:
        typeof data.source === "object"
          ? data.source.name
          : data.source || "Unknown",

      sourceUrl: data.url || "",

      author: data.author || "Unknown",
      authorRole: "Unknown", 


      topicTags: ["AI", "Automation", "Integration"],


      engagement: {
        likes: Math.floor(Math.random() * 500),
        shares: Math.floor(Math.random() * 200),
        comments: Math.floor(Math.random() * 100)
      },


      trendingComments: [
        "This could reshape enterprise workflows",
        "Integration is becoming the real bottleneck",
        "AI without orchestration is useless"
      ],


      image: data.urlToImage || "",


      collectedTimestamp: new Date().toISOString()
    }
  };
});

return items.map(item => {
  const root = item.json;


  const variants = root.variants || root.output?.variants || [];

  if (variants.length === 0) return item; 


  const bestVariant = [...variants].sort((a, b) => 
    (b.trendScore || 0) - (a.trendScore || 0)
  )[0];


  return {
    json: {
      ...root,
      ...bestVariant,

      variants: undefined 
    }
  };
});

return items.map(item => {

  const root = item.json;


  const variants =
    root.variants ||
    root.output?.variants ||
    [];

  const strongVariants = variants.filter(v => {
    if (!v.insight || v.insight.length < 50) return false;

    const text = ((v.insight || "") + (v.opinion || "")).toLowerCase();

    const banned = ["important", "growing trend", "significant"];
    if (banned.some(word => text.includes(word))) return false;

    return true;
  });

  return {
    json: {
      ...root,


      variants: strongVariants.length > 0 ? strongVariants : variants
    }
  };
});

return items.map(item => {
  return {
    json: {
      trend: item.json.trend || "",
      source: item.json.source || "Unknown",
      sourceUrl: item.json.sourceUrl || "",

      insight: item.json.insight || "",
      opinion: item.json.opinion || "",
      question: item.json.question || "",

      createdAt: item.json.createdAt || "",

      engagementLikes: item.json.engagementLikes || 0,
      engagementShares: item.json.engagementShares || 0,
      engagementComments: item.json.engagementComments || 0,

      trendScore: item.json.trendScore || 0,
      platform: item.json.platform || item.json.source || "Unknown",

      reviewNotes: "",

      // Guide reviews trend
      status: "Pending",

      // Draft not yet generated
      draftStatus: "NotCreated",


    }
  };
});

